#!/usr/bin/env python3
"""Bootstrap the full fire-external-baseline-reproduction scaffold.

This file is a self-contained snapshot generated because the GitHub connector
used in this session could not bulk-upload the full repository tree in one
operation. Run it from the repository root:

    python bootstrap_project.py

It extracts the complete scaffold into the current directory.
"""
from __future__ import annotations

import base64
import io
import tarfile
from pathlib import Path

SNAPSHOT_TAR_XZ_BASE64 = """

"""


def main() -> None:
    root = Path.cwd()
    raw = base64.b64decode("".join(SNAPSHOT_TAR_XZ_BASE64.split()))
    with tarfile.open(fileobj=io.BytesIO(raw), mode="r:xz") as archive:
        members = archive.getmembers()
        prefix = "fire-external-baseline-reproduction/"
        for member in members:
            if not member.name.startswith(prefix):
                continue
            member.name = member.name[len(prefix):]
            if not member.name:
                continue
            archive.extract(member, root)
    print("Extracted full external baseline reproduction scaffold into", root)
    print("Try: python scripts/run_all_baselines.py --methods direct_llm,vanilla_rag,ekell_style --limit 1")


if __name__ == "__main__":
    main()
